INSERT INTO MENSAJES (ID_MENSAJE, ID_USUARIO, NOMBRE, EMAIL, TIPO_CONSULTA, ASUNTO, CONTENIDO, FECHA_ENVIO, ES_LEIDO, ES_RESPONDIDO) VALUES 
(NEXT VALUE FOR Seq_Mensajes, 2, 'Marta Quirós', 'm.quirosmp@gmail.com', 'SUGERENCIA', 'MIEL PURA', 'żPodríais traer miel de la Sierra? Me cuesta encontrar una que sea 100% natural.', GETDATE(), 0, 0),
(NEXT VALUE FOR Seq_Mensajes, 4, 'Pablo Ruiz', 'pablo.ruiz@email.com', 'DUDA', 'HORARIO DE RECOGIDA', 'żEs posible recoger el pedido directamente en vuestra oficina para ahorrar el envío?', GETDATE(), 1, 1),
(NEXT VALUE FOR Seq_Mensajes, 5, 'Cristina Díaz', 'cristina.diaz@email.com', 'SUGERENCIA', 'CESTAS DE REGALO', 'Para Navidad sería un puntazo que hicierais cestas de madera con productos variados.', GETDATE(), 0, 0),
(NEXT VALUE FOR Seq_Mensajes, 17, 'Paco Garcia', 'paco.garcia@email.com', 'AGRICULTOR', 'NUEVA COSECHA', 'Hola, voy a empezar con la cosecha de espárragos. żCómo los subo a la plataforma?', GETDATE(), 0, 0),
(NEXT VALUE FOR Seq_Mensajes, 11, 'Sofía Castillo', 'sofia.castillo@email.com', 'SUGERENCIA', 'AVISO DE STOCK', 'Me gustaría recibir un email cuando volváis a tener tomates Raf, que siempre vuelo.', GETDATE(), 0, 0),
(NEXT VALUE FOR Seq_Mensajes, 16, 'David Molina', 'david.molina@email.com', 'DUDA', 'PAGO PAYPAL', 'żVais a meter PayPal como método de pago? Me daría más confianza.', GETDATE(), 0, 0),
(NEXT VALUE FOR Seq_Mensajes, 19, 'Elena Martínez', 'elena.martinez@email.com', 'AGRICULTOR', 'VISITA A FINCA', 'Me encantaría que vinierais a grabar un vídeo a mi finca para que los clientes vean cómo cultivamos.', GETDATE(), 1, 0),
(NEXT VALUE FOR Seq_Mensajes, 12, 'Hugo Santos', 'hugo.santos@email.com', 'SUGERENCIA', 'RECETAS', 'Estaría bien que junto a los productos pusierais alguna receta típica de la zona.', GETDATE(), 0, 0),
(NEXT VALUE FOR Seq_Mensajes, 18, 'Roberto Sanchez', 'roberto.sanchez@email.com', 'AGRICULTOR', 'LOGÍSTICA RECOGIDA', 'żPodéis pasar más temprano por mi finca? El sol de mediodía castiga mucho la verdura recién cortada.', GETDATE(), 0, 0),
(NEXT VALUE FOR Seq_Mensajes, 15, 'Alba Guerrero', 'alba.guerrero@email.com', 'SUGERENCIA', 'PACKS AHORRO', 'żHabrá packs de 5kg de patatas más baratos? Para familias grandes como la mía vendría genial.', GETDATE(), 0, 0),
(NEXT VALUE FOR Seq_Mensajes, NULL, 'Pedro Calvo', 'pedro.calvo@email.com', 'SUGERENCIA', 'MENOS PLÁSTICO', 'He visto vuestra publicidad. Si garantizáis cero plásticos en el envío, me hago cliente hoy mismo.', GETDATE(), 0,0),
(NEXT VALUE FOR Seq_Mensajes, NULL, 'Tońo Giménez', 'tono.gimenez@email.com', 'AGRICULTOR', 'CONDICIONES VENTA', 'Tengo una finca de lechugas en la ribera. żQué comisión os quedáis por venta?', GETDATE(), 0, 0);